    ki=1000000007ll;

    hamod=(one<<61)-1;

    kim=1;

    rep(i,t.size()){

        hikaku*=ki;

        h*=ki;

        kim*=ki;

        hikaku+=t[i];

        h+=s[i];

        hikaku%=hamod;

        h%=hamod;

        kim%=hamod;

    }

    rep(i,(int)s.size()-(int)t.size()+1){

        if (h==hikaku) {

            ans.emplace_back(i);

        }

        h*=ki;

        h%=hamod;

        h+=s[i+(int)t.size()];

        h%=hamod;

        h+=hamod;

        h-=s[i]*kim%hamod;

        h%=hamod;

    }

    return ans;

}

