    LL dist_yen[MAX_V];

    LL dist_snuku[MAX_V];



    VI u(m), v(m), a(m), b(m);

    REP(i, m) cin >> u[i] >> v[i] >> a[i] >> b[i], u[i]--, v[i]--;



    REP(i, m) {

        G_Yen[u[i]].push_back({v[i], a[i]});

        G_Yen[v[i]].push_back({u[i], a[i]});

        G_Snuku[u[i]].push_back({v[i], b[i]});

        G_Snuku[v[i]].push_back({u[i], b[i]});

    }



