template<typename T>

vector<T> dijkstra(const vector<vector<pair<int, T>>> &g, int s, T inf, T zero

    /* vector<int> prev */) {

  using PTI = pair<T, int>;

  int n = g.size();

  vector<T> d(n, inf);

  priority_queue<PTI, vector<PTI>, greater<PTI>> Q;

  d[s] = zero; Q.push({d[s], s});

  while (!Q.empty()) {

    int p = Q.top().second; Q.pop();

    for (const auto &f : g[p]) {

      int to = f.first; T cost = f.second;

      if (d[to] > d[p] + cost) {

        d[to] = d[p] + cost;

        /* prev[to] = p; */

        Q.push({d[to], to});

      }

    }

  }

  return d;

}



