            if (dist_yen[e.to] > dist_yen[v] + e.cost) {

                dist_yen[e.to] = dist_yen[v] + e.cost;

                Q.push(MP(dist_yen[e.to], e.to));

            }

        }

    }



}



void dijkstra_snuku(int n, int m, int s, LL dist_snuku[]) {

